
(()=>{
  if(window.__GOALOS_ASK_CONCIERGE_V60__) return; window.__GOALOS_ASK_CONCIERGE_V60__=true;
  const data=window.GOALOS_ASK_DATA||{routes:[],intents:[]};
  const norm=s=>(s||'').toLowerCase().normalize('NFKD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9]+/g,' ').trim();
  const basePrefix=()=>/\/evidence\//.test(location.pathname)?'../':'';
  const linkFor=href=>href.startsWith('http')?href:basePrefix()+href;
  const stop=new Set('the a an and or to of in on for with this that what where how why is are be do does can it me my our your goalos agi ai page site'.split(' '));
  function scoreRoute(q,r){const hay=norm([r.title,r.group,r.audience,r.description,r.outputArtifact,r.boundary].join(' '));const terms=norm(q).split(' ').filter(x=>x&&!stop.has(x));let s=0; for(const t of terms){ if(hay.includes(t)) s+=1; if(norm(r.title).includes(t)) s+=1.6; if(norm(r.group).includes(t)) s+=.7; } return s/(terms.length||1);}
  function matchIntent(q){const nq=norm(q);let best=null,score=0; for(const it of data.intents||[]){let s=0; for(const k of it.keywords||[]) if(nq.includes(norm(k))) s+=2+norm(k).split(' ').length*.2; if(s>score){score=s;best=it;}} return {intent:best,score};}
  function recommend(q){const {intent,score}=matchIntent(q); let routes=[]; let answer='I can help route this through the public proof institution. The safest next step is to inspect the matching proof page, evidence room, boundary, or complete route index.'; if(intent&&score>0){answer=intent.answer; routes=(intent.routes||[]).map(h=>data.routes.find(r=>r.href===h)).filter(Boolean);} const ranked=[...(data.routes||[])].map(r=>[scoreRoute(q,r),r]).filter(x=>x[0]>0).sort((a,b)=>b[0]-a[0]).map(x=>x[1]); for(const r of ranked){if(!routes.find(x=>x.href===r.href)) routes.push(r); if(routes.length>=5) break;} if(!routes.length) routes=(data.routes||[]).filter(r=>['experience-command.html','complete-route-index.html','command-center.html','canonical-proof-institution.html'].includes(r.href)); return {answer,routes:routes.slice(0,5),intent};}
  function install(){
    const box=document.createElement('div'); box.className='goalos-ask';
    box.innerHTML='<button class="goalos-ask__button" type="button" aria-expanded="false">Ask GoalOS</button><section class="goalos-ask__panel" role="dialog" aria-label="Ask GoalOS question router"><div class="goalos-ask__head"><div><small>browser-local question router</small><b>Ask GoalOS</b></div><button class="goalos-ask__close" type="button" aria-label="Close Ask GoalOS">×</button></div><div class="goalos-ask__quick"><button type="button" data-q="I am new. Where should I start?">Start</button><button type="button" data-q="How do I build an Evidence Docket?">Evidence</button><button type="button" data-q="Show me Loop to RSI governance">Loop → RSI</button><button type="button" data-q="What is the AGIALPHA token boundary?">AGIALPHA</button><button type="button" data-q="Find all pages">All pages</button></div><div class="goalos-ask__log" aria-live="polite"></div><div class="goalos-ask__composer"><textarea class="goalos-ask__input" aria-label="Ask a public-site question" placeholder="Ask: Where do I start? How do I inspect proof? What page explains RSI?" rows="1"></textarea><button class="goalos-ask__send" type="button">Ask</button></div><div class="goalos-ask__boundary">Local only: no account, no network request, no wallet, no analytics, no cookies, no browser storage, no user data retained.</div></section>';
    document.body.appendChild(box);
    const openBtn=box.querySelector('.goalos-ask__button'),panel=box.querySelector('.goalos-ask__panel'),closeBtn=box.querySelector('.goalos-ask__close'),log=box.querySelector('.goalos-ask__log'),input=box.querySelector('.goalos-ask__input'),send=box.querySelector('.goalos-ask__send');
    const show=()=>{panel.classList.add('open');openBtn.setAttribute('aria-expanded','true'); if(!log.dataset.seeded){bot('Ask any question about GoalOS. I answer locally, then route you to the right page. Try “Where should I start?”, “Explain Evidence Docket,” or “Open RSI Control Room.”'); log.dataset.seeded='1';} setTimeout(()=>input.focus(),20)};
    const hide=()=>{panel.classList.remove('open');openBtn.setAttribute('aria-expanded','false')};
    const add=(kind,html)=>{const m=document.createElement('div');m.className='goalos-ask__msg '+kind;m.innerHTML=html;log.appendChild(m);log.scrollTop=log.scrollHeight;};
    function routeCards(routes){return '<div class="goalos-ask__routes">'+routes.map(r=>'<a href="'+linkFor(r.href)+'"><small>'+esc(r.group||'Route')+'</small><strong>'+esc(r.title)+'</strong><span>'+esc(r.description||'Open this public-safe route.')+'</span></a>').join('')+'</div>';}
    function esc(s){return String(s||'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));}
    function bot(text,routes){add('assistant','<div>'+esc(text)+'</div>'+(routes?routeCards(routes):''));}
    function ask(q){q=(q||input.value||'').trim(); if(!q) return; add('user',esc(q)); input.value=''; const rec=recommend(q); const action=/^(open|go to|take me to|route me to|show me)\b/i.test(q); bot(rec.answer,rec.routes); if(action&&rec.routes&&rec.routes[0]){setTimeout(()=>{location.href=linkFor(rec.routes[0].href)},420);} }
    openBtn.addEventListener('click',()=>panel.classList.contains('open')?hide():show()); closeBtn.addEventListener('click',hide); send.addEventListener('click',()=>ask()); input.addEventListener('keydown',e=>{if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();ask();}}); box.querySelectorAll('[data-q]').forEach(b=>b.addEventListener('click',()=>{show();ask(b.getAttribute('data-q'))})); document.addEventListener('keydown',e=>{if(e.key==='Escape')hide(); if((e.ctrlKey||e.metaKey)&&e.shiftKey&&e.key.toLowerCase()==='k'){e.preventDefault();show();}});
  }
  if(document.readyState==='loading')document.addEventListener('DOMContentLoaded',install); else install();
})();
